(window.webpackJsonp=window.webpackJsonp||[]).push([[122],{1507:function(n){n.exports=JSON.parse('{"content":"<p>\u6700\u8fd1\u5728\u5408\u5e76\u4e00\u4e9b\u9879\u76ee\uff0c\u6709\u4e9b\u7528<code>Vue</code>\uff0c\u6709\u7684\u7528<code>React</code>\uff0c\u9700\u8981\u5c06\u5b83\u4eec\u6574\u5408\u6210\u4e00\u4e2a\u9879\u76ee\uff0c\u5c31\u7528\u4e86\u81ea\u5df1\u7684\u591a\u9875\u9762\u9879\u76ee\u6846\u67b6\uff0c\u51e0\u70b9\u611f\u53d7\u548c\u9700\u8981\u6539\u8fdb\u7684\u60f3\u6cd5\u8bb0\u5f55\u4e0b\u3002</p>\\n<p>\u4e00\u4e9b\u611f\u53d7\uff1a</p>\\n<ul>\\n<li>\u603b\u7684\u6765\u8bf4\u5408\u5e76\u8fd8\u662f\u6bd4\u8f83\u987a\u5229\u7684\uff0c\u4e00\u4e9b\u4f9d\u8d56\u7ec4\u4ef6\u6bd4\u8f83\u65e7\uff0c\u56e0\u6b64\u53e6\u5916\u4e00\u4e9b\u4f9d\u8d56\u7ec4\u4ef6\u5fc5\u987b\u964d\u7ea7\u624d\u80fd\u517c\u5bb9\u4f7f\u7528\uff1b</li>\\n<li>\u7531\u4e8e\u76ee\u524d\u4e0d\u540c\u7684\u6846\u67b6\u8fd8\u662f\u5360\u7528\u4e0d\u540c\u9875\u9762\uff0c\u9700\u8981\u53e6\u5916\u4e00\u4e2a\u72ec\u7acb\u7684\u5bfc\u822a\u680f\uff1b</li>\\n<li>\u53e6\u5916\uff0c\u5982\u679c\u9875\u9762\u540d\u79f0\u548c\u8def\u7531\u540d\u79f0\u4e5f\u662f\u4e0d\u80fd\u91cd\u590d\uff0c\u5426\u5219\u4f1a\u9020\u6210\u51b2\u7a81</li>\\n</ul>\\n<p>\u9700\u8981\u6539\u8fdb\uff1a</p>\\n<ul>\\n<li>\u9875\u9762\u540d\u79f0\u548c\u8def\u7531\u540d\u79f0\u51b2\u7a81\u95ee\u9898\uff0c\u8003\u8651\uff1a(\u68c0\u6d4b\u673a\u5236\uff1f\u65b0\u7684\u89c4\u5219(<code>spa</code>\u76ee\u5f55\u4e0b\u4e0d\u7f16\u8bd1\u5176\u4ed6\u9875\u9762)\uff1f)</li>\\n<li>\u6846\u67b6\u5408\u5e76\u4e0d\u80fd\u505a\u5230\u540c\u9875\u9762\u7684\u5408\u5e76\uff0c\u5c1d\u8bd5\uff1a(\u591a\u4e2a\u524d\u7aef\u6846\u67b6)\uff0c\u8003\u8651\uff1a\uff08\u6846\u67b6\u4e4b\u524d\u901a\u4fe1\u95ee\u9898\uff09\uff0c\u53c2\u8003\uff1a\uff08\u5fae\u524d\u7aef\uff09</li>\\n<li>\u9875\u9762\u56fa\u5b9a\u903b\u8f91\u6587\u4ef6\u592a\u591a\uff0c\u8003\u8651\u590d\u7528</li>\\n</ul>\\n<p>\u603b\u7684\u6765\u8bf4\uff0c\u5c0f\u95ee\u9898\u9047\u5230\u5f88\u591a\uff0c\u4f46\u4e5f\u5bb9\u6613\u89e3\u51b3\uff0c\u5927\u95ee\u9898\u5f80\u5f80\u90fd\u662f\u7ed3\u6784\u6027\u7684\u95ee\u9898\uff0c\u5fc5\u987b\u4e3b\u52a8\u53bb\u53d1\u73b0\uff0c\u591a\u65b9\u9762\u8003\u8651\u3002</p>\\n"}')}}]);